import React from "react";
import { useSelector } from "react-redux";

function InteractionForm() {
  const form = useSelector((state) => state.form);

  const sentimentEmoji = {
    positive: "😊",
    neutral: "😐",
    negative: "😞",
  };

  return (
    <div>
      <h2>Log HCP Interaction</h2>

      <input placeholder="HCP Name" value={form.hcp_name || ""} readOnly />
      <input placeholder="Interaction Type" value={form.interaction_type || ""} readOnly />
      <input placeholder="Date" value={form.date || ""} readOnly />
      <input placeholder="Time" value={form.time || ""} readOnly />
      <textarea placeholder="Topics Discussed" value={form.topics || ""} readOnly />
      <textarea placeholder="Outcomes" value={form.outcomes || ""} readOnly />
      <textarea placeholder="Follow Up" value={form.followup || ""} readOnly />

      {/* Sentiment */}
      {form.sentiment && (
        <div className="form-field">
          <strong>Sentiment: </strong>
          <span>{sentimentEmoji[form.sentiment]} {form.sentiment}</span>
        </div>
      )}

      {/* Recommendations */}
      {form.recommendations && form.recommendations.length > 0 && (
        <div className="form-field recommendations">
          <strong>Next Actions:</strong>
          <ul>
            {form.recommendations.map((r, i) => (
              <li key={i}>{r}</li>
            ))}
          </ul>
        </div>
      )}

      {/* Meeting Conflict */}
      {form.meeting_conflict && (
        <div className="form-field conflict">
          ⚠ Meeting time conflict detected!
        </div>
      )}

      {/* Confidence */}
      {form.confidence && (
        <div className="form-field confidence">
          <strong>Confidence:</strong>
          {Object.entries(form.confidence).map(([k,v]) => (
            <div key={k}>{k}: {v}%</div>
          ))}
        </div>
      )}
    </div>
  );
}

export default InteractionForm;
